parameters.jsonBody:
={{ {
    "embeds": [
      {
        "title": "CoinPilot Weekly Exit Report",
        "color": 3447003,
        "description": String((
          "기간: " + String(($json["period_start"] || ($json["body"] && $json["body"]["period_start"]) || "-")) +
          " ~ " + String(($json["period_end"] || ($json["body"] && $json["body"]["period_end"]) || "-")) +
          "\nSELL 샘플: " + String(($json["total_sells"] || ($json["body"] && $json["body"]["total_sells"]) || 0)) + "건" +
          "\n\n요약:\n" + String(($json["summary"] || ($json["body"] && $json["body"]["summary"]) || "요약 없음"))
        ).substring(0, 1800)),
        "fields": [
          {
            "name": "제안",
            "value": String((((($json["suggestions"] || ($json["body"] && $json["body"]["suggestions"])) || [])).join('\n')) || "없음").substring(0, 1000),
            "inline": false
          },
          {
            "name": "Rule Funnel",
            "value": String(((Object.entries((((($json["rule_funnel"] || ($json["body"] && $json["body"]["rule_funnel"])) || {}).by_regime) || {})).map(([regime, bucket]) => regime + ": rule_pass=" + String((((bucket["rule_pass"] || {})["count"]) || 0)) + ", risk_reject=" + String((((bucket["risk_reject"] || {})["count"]) || 0)) + ", prefilter=" + String((((bucket["ai_prefilter_reject"] || {})["count"]) || 0)) + ", guardrail=" + String((((bucket["ai_guardrail_block"] || {})["count"]) || 0)) + ", ai_confirm=" + String((((bucket["ai_confirm"] || {})["count"]) || 0)) + ", ai_reject=" + String((((bucket["ai_reject"] || {})["count"]) || 0))).join('\n')) || "없음").substring(0, 1000),
            "inline": false
          },
          {
            "name": "Rule Funnel 제안",
            "value": String((((($json["rule_funnel_suggestions"] || ($json["body"] && $json["body"]["rule_funnel_suggestions"])) || [])).join('\n')) || "없음").substring(0, 1000),
            "inline": false
          }
        ],
        "footer": { "text": "CoinPilot" },
        "timestamp": String(($json["timestamp"] || ($json["body"] && $json["body"]["timestamp"]) || new Date().toISOString()))
      }
    ]
  } }}
